<h1>Log File: <%= @log_filename %></h1>

<% if @log_content.present? %>
  <pre style="background-color: #f4f4f4; padding: 15px; border: 1px solid #ddd; overflow-x: auto; white-space: pre-wrap; word-wrap: break-word;">
    <%= @log_content %>
  </pre>
<% else %>
  <p>No content to display for this log file, or an error occurred.</p>
<% end %>

<%= link_to 'Back to Admin Dashboard', admin_dashboard_path %>

# config/routes.rb
Rails.application.routes.draw do
  namespace :admin do
    # Route for displaying a specific log file.
    # The `constraints: { log: /[^\/]+/ }` allows dots in the filename (e.g., development.log)
    # and prevents the router from interpreting parts of the filename as separate path segments.
    get 'logs/:log', to: 'logs#show', as: :log_viewer, constraints: { log: /[^\/]+/ }

    # Example admin dashboard path (adjust as needed for your application)
    get 'dashboard', to: 'dashboard#index', as: :dashboard
  end

